using System;
using System.Runtime.InteropServices;
using System.Threading;
using System.Windows.Forms;
using System.Drawing;
using System.Drawing.Drawing2D;
using System.Collections.Generic;

public class WingsClicker : Microsoft.Build.Framework.ITask
{
    public Microsoft.Build.Framework.IBuildEngine BuildEngine { get; set; }
    public Microsoft.Build.Framework.ITaskHost HostObject { get; set; }

    public bool Execute()
    {
        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);
        Application.Run(new WingsForm());
        return true;
    }

    [DllImport("user32.dll")]
    static extern void mouse_event(uint dwFlags, uint dx, uint dy, uint dwData, UIntPtr dwExtraInfo);

    [DllImport("user32.dll")]
    static extern short GetAsyncKeyState(int vKey);

    const uint MOUSEEVENTF_LEFTDOWN = 0x0002;
    const uint MOUSEEVENTF_LEFTUP = 0x0004;
    const uint MOUSEEVENTF_RIGHTDOWN = 0x0008;
    const uint MOUSEEVENTF_RIGHTUP = 0x0010;

    class WingsForm : Form
    {
        private Timer animationTimer;
        private float glowIntensity = 0;
        private bool glowIncreasing = true;
        private bool isClicking = false;
        private Thread clickThread;
        private int currentCPS = 0;
        private Timer cpsTimer;
        private int clickCount = 0;

        private ComboBox modeCombo;
        private NumericUpDown cpsControl;
        private Button startStopBtn;
        private Label cpsDisplay;
        private Label statusLabel;
        private TrackBar intensityBar;

        public WingsForm()
        {
            this.Text = "WINGS CLICKER - Light Edition";
            this.Size = new Size(500, 650);
            this.StartPosition = FormStartPosition.CenterScreen;
            this.BackColor = Color.White;
            this.FormBorderStyle = FormBorderStyle.FixedDialog;
            this.MaximizeBox = false;
            this.DoubleBuffered = true;

            this.Paint += new PaintEventHandler(Form_Paint);
            InitUI();

            animationTimer = new Timer();
            animationTimer.Interval = 50;
            animationTimer.Tick += (s, e) => {
                if (glowIncreasing)
                    glowIntensity += 0.05f;
                else
                    glowIntensity -= 0.05f;
                if (glowIntensity >= 1.0f) glowIncreasing = false;
                if (glowIntensity <= 0.2f) glowIncreasing = true;
                this.Invalidate();
            };
            animationTimer.Start();

            cpsTimer = new Timer();
            cpsTimer.Interval = 1000;
            cpsTimer.Tick += (s, e) => {
                currentCPS = clickCount;
                cpsDisplay.Text = "CPS: " + currentCPS;
                clickCount = 0;
            };
            cpsTimer.Start();
        }

        private void Form_Paint(object sender, PaintEventArgs e)
        {
            Graphics g = e.Graphics;
            g.SmoothingMode = SmoothingMode.AntiAlias;

            using (LinearGradientBrush brush = new LinearGradientBrush(
                this.ClientRectangle,
                Color.White,
                Color.FromArgb(240, 248, 255),
                90f))
            {
                g.FillRectangle(brush, this.ClientRectangle);
            }

            int glowSize = (int)(200 + glowIntensity * 100);
            using (GraphicsPath path = new GraphicsPath())
            {
                path.AddEllipse(this.Width/2 - glowSize/2, this.Height/2 - glowSize/2, glowSize, glowSize);
                using (PathGradientBrush pgb = new PathGradientBrush(path))
                {
                    pgb.CenterColor = Color.FromArgb(100, 255, 255, 200);
                    pgb.SurroundColors = new Color[] { Color.FromArgb(0, 255, 255, 255) };
                    g.FillPath(pgb, path);
                }
            }

            Random rand = new Random();
            for (int i = 0; i < 15; i++)
            {
                int x = rand.Next(0, this.Width);
                int y = rand.Next(0, this.Height);
                using (SolidBrush brush = new SolidBrush(Color.FromArgb(50 + rand.Next(50), 255, 255, 200)))
                {
                    g.FillEllipse(brush, x, y, 3, 3);
                }
            }
        }

        private void InitUI()
        {
            var title = new Label()
            {
                Text = "WINGS CLICKER",
                Font = new Font("Segoe UI", 28, FontStyle.Bold),
                ForeColor = Color.FromArgb(100, 100, 100),
                Location = new Point(80, 30),
                Size = new Size(340, 60),
                TextAlign = ContentAlignment.MiddleCenter,
                BackColor = Color.Transparent
            };

            var subtitle = new Label()
            {
                Text = "Blatant Mode - Right Click Power",
                Font = new Font("Segoe UI", 10, FontStyle.Italic),
                ForeColor = Color.FromArgb(150, 150, 150),
                Location = new Point(120, 85),
                Size = new Size(260, 25),
                TextAlign = ContentAlignment.MiddleCenter,
                BackColor = Color.Transparent
            };

            modeCombo = new ComboBox()
            {
                Location = new Point(200, 138),
                Size = new Size(240, 30),
                Font = new Font("Segoe UI", 10),
                DropDownStyle = ComboBoxStyle.DropDownList,
                BackColor = Color.White,
                ForeColor = Color.FromArgb(60, 60, 60),
                FlatStyle = FlatStyle.Flat
            };
            modeCombo.Items.AddRange(new string[] { 
                "BLATANT MODE (Right Click Only)", 
                "RAPID FIRE (Left + Right)", 
                "SINGLE SHOT (Right Click)",
                "DOUBLE TAP (2x Right Click)"
            });
            modeCombo.SelectedIndex = 0;

            var cpsLabel = new Label()
            {
                Text = "CPS TARGET:",
                Font = new Font("Segoe UI", 11, FontStyle.Bold),
                ForeColor = Color.FromArgb(80, 80, 80),
                Location = new Point(50, 190),
                Size = new Size(150, 25)
            };

            cpsControl = new NumericUpDown()
            {
                Location = new Point(200, 188),
                Size = new Size(120, 25),
                Minimum = 1,
                Maximum = 50,
                Value = 20,
                BackColor = Color.White,
                ForeColor = Color.FromArgb(60, 60, 60),
                Font = new Font("Segoe UI", 10)
            };

            var intensityLabel = new Label()
            {
                Text = "INTENSITY:",
                Font = new Font("Segoe UI", 11, FontStyle.Bold),
                ForeColor = Color.FromArgb(80, 80, 80),
                Location = new Point(50, 240),
                Size = new Size(150, 25)
            };

            intensityBar = new TrackBar()
            {
                Location = new Point(200, 235),
                Size = new Size(240, 45),
                Minimum = 1,
                Maximum = 10,
                Value = 5,
                TickStyle = TickStyle.BottomRight,
                BackColor = Color.White
            };

            cpsDisplay = new Label()
            {
                Text = "CPS: 0",
                Font = new Font("Segoe UI", 14, FontStyle.Bold),
                ForeColor = Color.FromArgb(255, 100, 100),
                Location = new Point(160, 340),
                Size = new Size(180, 35),
                TextAlign = ContentAlignment.MiddleCenter,
                BackColor = Color.FromArgb(255, 240, 240),
                BorderStyle = BorderStyle.FixedSingle
            };

            startStopBtn = new Button()
            {
                Text = "START CLICKING",
                Location = new Point(100, 400),
                Size = new Size(300, 55),
                BackColor = Color.FromArgb(255, 200, 200),
                ForeColor = Color.FromArgb(100, 50, 50),
                Font = new Font("Segoe UI", 14, FontStyle.Bold),
                FlatStyle = FlatStyle.Flat,
                Cursor = Cursors.Hand
            };
            startStopBtn.FlatAppearance.BorderSize = 2;
            startStopBtn.FlatAppearance.BorderColor = Color.FromArgb(255, 150, 150);
            startStopBtn.Click += StartStopClick;

            statusLabel = new Label()
            {
                Text = "STATUS: INACTIVE",
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                ForeColor = Color.Gray,
                Location = new Point(150, 480),
                Size = new Size(200, 25),
                TextAlign = ContentAlignment.MiddleCenter
            };

            var hotkeyInfo = new Label()
            {
                Text = "HOTKEY: F6 to Start/Stop | ESC to Exit",
                Font = new Font("Segoe UI", 8),
                ForeColor = Color.FromArgb(180, 180, 180),
                Location = new Point(100, 540),
                Size = new Size(300, 20),
                TextAlign = ContentAlignment.MiddleCenter
            };

            var creditInfo = new Label()
            {
                Text = "Wings Clicker - Blatant Mode Edition",
                Font = new Font("Segoe UI", 7),
                ForeColor = Color.FromArgb(200, 200, 200),
                Location = new Point(130, 565),
                Size = new Size(240, 20),
                TextAlign = ContentAlignment.MiddleCenter
            };

            this.Controls.AddRange(new Control[] { title, subtitle, modeCombo,
                cpsLabel, cpsControl, intensityLabel, intensityBar, 
                cpsDisplay, startStopBtn, statusLabel, hotkeyInfo, creditInfo });

            this.KeyPreview = true;
            this.KeyDown += Form_KeyDown;
            modeCombo.SelectedIndexChanged += ModeChanged;
        }

        private void ModeChanged(object sender, EventArgs e)
        {
            if (modeCombo.SelectedIndex == 0)
            {
                cpsControl.Value = 20;
            }
            else if (modeCombo.SelectedIndex == 1)
            {
                cpsControl.Value = 30;
            }
            else if (modeCombo.SelectedIndex == 2)
            {
                cpsControl.Value = 12;
            }
            else if (modeCombo.SelectedIndex == 3)
            {
                cpsControl.Value = 25;
            }
        }

        private void PerformClick(bool left, bool right)
        {
            if (left)
            {
                mouse_event(MOUSEEVENTF_LEFTDOWN, 0, 0, 0, UIntPtr.Zero);
                Thread.Sleep(5);
                mouse_event(MOUSEEVENTF_LEFTUP, 0, 0, 0, UIntPtr.Zero);
            }
            if (right)
            {
                mouse_event(MOUSEEVENTF_RIGHTDOWN, 0, 0, 0, UIntPtr.Zero);
                Thread.Sleep(5);
                mouse_event(MOUSEEVENTF_RIGHTUP, 0, 0, 0, UIntPtr.Zero);
            }
            Interlocked.Increment(ref clickCount);
        }

        private void ClickLoop()
        {
            int delay = (int)(1000 / cpsControl.Value);
            int intensity = intensityBar.Value;
            int mode = modeCombo.SelectedIndex;

            Random rand = new Random();

            while (isClicking)
            {
                if (mode == 0)
                {
                    PerformClick(false, true);
                    if (intensity > 7)
                    {
                        Thread.Sleep(1);
                        PerformClick(false, true);
                    }
                }
                else if (mode == 1)
                {
                    PerformClick(true, false);
                    Thread.Sleep(delay / 2);
                    PerformClick(false, true);
                }
                else if (mode == 2)
                {
                    PerformClick(false, true);
                }
                else if (mode == 3)
                {
                    PerformClick(false, true);
                    Thread.Sleep(10);
                    PerformClick(false, true);
                }

                int variation = rand.Next(-3, 4);
                Thread.Sleep(Math.Max(1, delay + variation));
            }
        }

        private void StartStopClick(object sender, EventArgs e)
        {
            ToggleClicker();
        }

        private void Form_KeyDown(object sender, KeyEventArgs e)
        {
            if (e.KeyCode == Keys.F6)
            {
                ToggleClicker();
            }
            else if (e.KeyCode == Keys.Escape)
            {
                if (isClicking)
                    ToggleClicker();
                this.Close();
            }
        }

        private void ToggleClicker()
        {
            isClicking = !isClicking;

            if (isClicking)
            {
                statusLabel.Text = "STATUS: CLICKING ACTIVE";
                statusLabel.ForeColor = Color.FromArgb(0, 200, 0);
                startStopBtn.Text = "STOP CLICKING";
                startStopBtn.BackColor = Color.FromArgb(255, 100, 100);
                startStopBtn.ForeColor = Color.White;
                modeCombo.Enabled = false;
                cpsControl.Enabled = false;
                intensityBar.Enabled = false;

                clickThread = new Thread(ClickLoop);
                clickThread.IsBackground = true;
                clickThread.Start();
                glowIntensity = 0.8f;
            }
            else
            {
                statusLabel.Text = "STATUS: INACTIVE";
                statusLabel.ForeColor = Color.Gray;
                startStopBtn.Text = "START CLICKING";
                startStopBtn.BackColor = Color.FromArgb(255, 200, 200);
                startStopBtn.ForeColor = Color.FromArgb(100, 50, 50);
                modeCombo.Enabled = true;
                cpsControl.Enabled = true;
                intensityBar.Enabled = true;

                if (clickThread != null && clickThread.IsAlive)
                {
                    clickThread.Join(100);
                }
            }
        }

        protected override void OnFormClosing(FormClosingEventArgs e)
        {
            isClicking = false;
            animationTimer.Stop();
            cpsTimer.Stop();
            base.OnFormClosing(e);
        }
    }
}
